class Inventory:
    def __init__(self):
        self.total_stock = 0

    def add_stock(self, quantity):
        self.total_stock += quantity

    def remove_stock(self, quantity):
        if quantity <= self.total_stock:
            self.total_stock -= quantity
        else:
            print("Not enough stock to remove.")

class CategoryInventory(Inventory):
    def __init__(self, category_name):
        super().__init__()
        self.category_name = category_name


class SpecialCategoryInventory(CategoryInventory):
    def __init__(self, category_name, special_feature):
        super().__init__(category_name)
        self.special_feature = special_feature

    def display_category_details(self):
        print(f"Category: {self.category_name}")
        print(f"Special Feature: {self.special_feature}")

# Do not modify the code below. This function will be called during testing.
def default_test():
    special_inventory = SpecialCategoryInventory("Electronics", "Latest Tech")
    print(special_inventory.category_name)
    print(special_inventory.special_feature)
    special_inventory.display_category_details()
    special_inventory.add_stock(50)
    print(special_inventory.total_stock)
    special_inventory.remove_stock(20)
    print(special_inventory.total_stock)
